+import { TokenManager } from './token';
+
+test('coalesces concurrent refreshes into one call', async () => {
+  let calls = 0;
+  const mgr = new TokenManager();
+  (mgr as any).refresh = async () => {
+    calls++;
+    return 'tok';
+  };
+  (mgr as any).expiresAt = 0;
+  const [a, b] = await Promise.all([mgr.getToken(), mgr.getToken()]);
+  expect(a).toBe('tok');
+  expect(b).toBe('tok');
+  expect(calls).toBe(1);
+});
